import{_ as t,o,c as a,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Liveview (New)","description":"","frontmatter":{"title":"Liveview (New)","slug":"liveview-new"},"headers":[],"relativePath":"account-hub/liveview-new.md","filePath":"account-hub/liveview-new.md"}'),n={name:"account-hub/liveview-new.md"};function s(r,e,l,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h2 id="get-started" tabindex="-1">Get started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get started&quot;">​</a></h2><p>To access Liveview, go to <strong>Configuration</strong> <strong>&gt;</strong> <strong>Testing &amp; Monitoring</strong>, then select the <strong>Liveview</strong> tab.</p><div class="danger custom-block"><p class="custom-block-title">Don&#39;t see this page yet?</p><p>The Testing &amp; Monitoring page is part of the <a href="./new-branch-overview.html">new Branch</a> experience. This page is being rolled out to customers in phases through 2026. While you&#39;re waiting for access, you can explore this article to familiarize yourself with the new functionality.</p></div><h3 id="_1-choose-an-event-type" tabindex="-1">1. Choose an event type <a class="header-anchor" href="#_1-choose-an-event-type" aria-label="Permalink to &quot;1. Choose an event type&quot;">​</a></h3><p>Select the event type you want to view from the dropdown menu in the upper left.</p><h3 id="_2-add-filters-optional" tabindex="-1">2. Add filters (optional) <a class="header-anchor" href="#_2-add-filters-optional" aria-label="Permalink to &quot;2. Add filters (optional)&quot;">​</a></h3><p>Select <strong>Build Query</strong> to open the query builder modal. Here you can:</p><ul><li>Change the <strong>Event Type</strong> from the dropdown.</li><li>Add filters by selecting a field, operator, and value.</li><li>Select <strong>+ Add filter</strong> to add additional filters.</li></ul><p>Select <strong>Save</strong> to apply your filters.</p><p>Some of the most useful filters include <code>name</code> (for example, <code>PURCHASE</code>), <code>feature</code>, <code>channel</code>, <code>campaign</code>, and device identifiers like <code>IDFA</code>.</p><h3 id="_4-customize-columns-optional" tabindex="-1">4. Customize columns (optional) <a class="header-anchor" href="#_4-customize-columns-optional" aria-label="Permalink to &quot;4. Customize columns (optional)&quot;">​</a></h3><p>Select the <strong>Columns</strong> dropdown to show or hide columns in the results table. You can search for available columns and check or uncheck them to customize your view.</p><h3 id="_5-view-webhook-records" tabindex="-1">5. View Webhook records <a class="header-anchor" href="#_5-view-webhook-records" aria-label="Permalink to &quot;5. View Webhook records&quot;">​</a></h3><p>To see the webhook request and response for debugging, select webhooks from the event type dropdown. This allows you to see what information is getting sent and whether it was successful (200 status code) or not (400 or 500 status code).</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If you&#39;re trying to view Webhook Records going to a data integration, you&#39;ll need to filter by <code>webhook_partner_key</code> and specify the value in the format <code>di_partner_name</code>. For example, Adobe Analytics Processing Rules is <code>di_adobe_analytics_pr</code>, Mixpanel is <code>di_mixpanel</code>. If you don&#39;t add this filter, the webhook records for those data integrations will not show.</p></div><h2 id="supported-event-types" tabindex="-1">Supported event types <a class="header-anchor" href="#supported-event-types" aria-label="Permalink to &quot;Supported event types&quot;">​</a></h2><p>Liveview enables you to debug the following event types:</p><ul><li>click</li><li>branch cta view</li><li>sms sent</li><li>open</li><li>install</li><li>reinstall</li><li>web session start</li><li>pageview</li><li>content event</li><li>commerce event</li><li>custom event</li><li>user lifecycle event</li><li>webhooks</li></ul><p>Liveview allows advanced filtering on a number of dimensions, including per-event and per-device dimensions not surfaced elsewhere in Branch. Access to this data is determined by the <a href="./add-manage-users-roles-permissions-access.html#access-levels">Sensitive Data access level</a>.</p><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>Why is my link showing the same campaign name even though I&#39;m sending dynamic values via query parameters?</summary><p>We don&#39;t allow you to override default values set for analytics parameters (&#39;~channel&#39;, &#39;~tags&#39;, &#39;~campaign&#39;, &#39;~feature&#39;) at the link level via query parameters. This is done to prevent spam.</p></details><details><summary>Why am I able to see revenue data on Liveview but not on the analytics page?</summary><p>Revenue data will only populate for <code>PURCHASE</code> events. The event must be a standard Branch Commerce Event with the type <code>PURCHASE</code>, as outlined in the Commerce table in this <a href="./track-branch-events.html#track-commerce-events">section</a>.</p><p>If you use a different type of event other than a <code>PURCHASE</code> event, you&#39;ll only see the data in Liveview, and the same data will not populate the dashboard.</p><p>For more information, refer to our documentation on <a href="./track-branch-events.html">Tracking Commerce, Content, Lifecycle and Custom Events</a>.</p></details>',22)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
